INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1239, '韩国计划将可再生能源发电占比提升至20%', '韩国气候能源环境部6日宣布，韩国计划到2030年将可再生能源发电占比提升到至少20%，以降低对进口能源的高度依赖，并应对高端产业发展带来的电力需求增加。根据气候能源环境部在内阁会议上汇报的这项计划，韩国将大力发展太阳能与风能发电，到2030年将可再生能源供电规模扩大至100吉瓦，到2040年逐步关停60座燃煤电厂。该部门还表示，将力争使新能源汽车占新车销量比例到2030年达到40%。 (新华社)', '韩国气候能源环境部6日宣布，韩国计划到2030年将可再生能源发电占比提升到至少20%，以降低对进口能源的高度依赖，并应对高端产业发展带来的电力需求增加。根据气候能源环境部在内阁会议上汇报的这项计划，韩国将大力发展太阳能与风能发电，到2030年将可再生能源供电规模扩大至100吉瓦，到2040年逐步关停60座燃煤电厂。该部门还表示，将力争使新能源汽车占新车销量比例到2030年达到40%。 (新华社)', 8, '36氪', 'https://36kr.com/newsflashes/3755019581506307?f=rss', '', 'industry', '["\u79d1\u6280", "\u521b\u4e1a", "\u6295\u8d44"]', '2026-04-06 07:33:21.000000', '2026-04-07 06:26:55.682484', 'https://36kr.com/newsflashes/3755019581506307?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1240, '司美格鲁肽口服减重药已开出超60万张处方，市场空间还有多大', '根据诺和诺德最新披露的数据，目前旗下司美格鲁肽口服减重药的处方量超过60万张。瑞银集团（UBS）估计，礼来公司的口服减重药物与诺和诺德的口服版司美格鲁肽在2026年合计将创造约50亿美元的收入。不过，在诺和诺德CEO看来，减重药市场规模庞大，制药行业目前仅触及“皮毛”。他表示，包括诺和诺德、礼来以及美国的多款减重药复方制剂生产商在内，目前所提供的减重药合计仅能满足10%至15%的肥胖症患者需求。 (第一财经)', '根据诺和诺德最新披露的数据，目前旗下司美格鲁肽口服减重药的处方量超过60万张。瑞银集团（UBS）估计，礼来公司的口服减重药物与诺和诺德的口服版司美格鲁肽在2026年合计将创造约50亿美元的收入。不过，在诺和诺德CEO看来，减重药市场规模庞大，制药行业目前仅触及“皮毛”。他表示，包括诺和诺德、礼来以及美国的多款减重药复方制剂生产商在内，目前所提供的减重药合计仅能满足10%至15%的肥胖症患者需求。 (第一财经)', 8, '36氪', 'https://36kr.com/newsflashes/3755018936533512?f=rss', '', 'industry', '["\u79d1\u6280", "\u521b\u4e1a", "\u6295\u8d44"]', '2026-04-06 07:22:47.000000', '2026-04-07 06:26:55.682494', 'https://36kr.com/newsflashes/3755018936533512?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1241, '媒体：全球最大的电池制造商宁德时代将雄心拓展至远洋 计划今年将其海洋事业部规模扩大一倍', '据英国金融时报报道，全球最大的电池制造商宁德时代决定“全力以赴”推动全球航运业的电动化进程，试图将其在电动汽车领域的成功经验复制到海上领域。作为宁德时代对这一领域投入决心的体现，负责其海洋业务部门的Su Yi表示，她计划今年将团队规模扩大一倍多，达到约 500 人。Su表示，目前的重点是生产出能满足在水上运行的“极高”要求的电池，包括电池单元的长寿命以及在海洋环境中的安全性。宁德时代拒绝提供销售目标，但一位发言人表示，其对“强劲的市场潜力”“非常有信心”。（新浪财经）', '据英国金融时报报道，全球最大的电池制造商宁德时代决定“全力以赴”推动全球航运业的电动化进程，试图将其在电动汽车领域的成功经验复制到海上领域。作为宁德时代对这一领域投入决心的体现，负责其海洋业务部门的Su Yi表示，她计划今年将团队规模扩大一倍多，达到约 500 人。Su表示，目前的重点是生产出能满足在水上运行的“极高”要求的电池，包括电池单元的长寿命以及在海洋环境中的安全性。宁德时代拒绝提供销售目标，但一位发言人表示，其对“强劲的市场潜力”“非常有信心”。（新浪财经）', 8, '36氪', 'https://36kr.com/newsflashes/3754997579662089?f=rss', '', 'industry', '["\u79d1\u6280", "\u521b\u4e1a", "\u6295\u8d44"]', '2026-04-06 07:08:59.000000', '2026-04-07 06:26:55.682505', 'https://36kr.com/newsflashes/3754997579662089?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1242, '苹果首款折叠屏手机已在试产', '记者4月6日从产业链人士处获悉，富士康已在试产苹果折叠屏iPhone手机。2025年，记者从供应链公司获悉，苹果给供应商提供的出货目标指引为2026年下半年推出首款折叠屏手机，是一款大折叠屏iPhone。 (中证金牛座)', '记者4月6日从产业链人士处获悉，富士康已在试产苹果折叠屏iPhone手机。2025年，记者从供应链公司获悉，苹果给供应商提供的出货目标指引为2026年下半年推出首款折叠屏手机，是一款大折叠屏iPhone。 (中证金牛座)', 8, '36氪', 'https://36kr.com/newsflashes/3754994635752193?f=rss', '', 'industry', '["\u79d1\u6280", "\u521b\u4e1a", "\u6295\u8d44"]', '2026-04-06 06:58:04.000000', '2026-04-07 06:26:55.682515', 'https://36kr.com/newsflashes/3754994635752193?f=rss', 0.0, 0);
