INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1247, '商务部电子商务司负责人解读《关于更好服务实体经济 推进电子商务高质量发展的指导意见》', '36氪获悉，近日，商务部会同中央网信办、工业和信息化部、农业农村部、文化和旅游部、市场监管总局等5部门印发《关于更好服务实体经济推进电子商务高质量发展的指导意见》（下称《意见》），商务部电子商务司负责人就《意见》进行了解读。', '36氪获悉，近日，商务部会同中央网信办、工业和信息化部、农业农村部、文化和旅游部、市场监管总局等5部门印发《关于更好服务实体经济推进电子商务高质量发展的指导意见》（下称《意见》），商务部电子商务司负责人就《意见》进行了解读。', 8, '36氪', 'https://36kr.com/newsflashes/3754841165103624?f=rss', '', 'industry', '["\u79d1\u6280", "\u521b\u4e1a", "\u6295\u8d44"]', '2026-04-06 04:35:51.000000', '2026-04-07 06:26:55.682581', 'https://36kr.com/newsflashes/3754841165103624?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1248, '红果短剧：针对近期AI短剧素材违规使用问题频发的情况，已处置作品670部', '36氪获悉，红果短剧官方账号4月6日发布《关于持续治理AI短剧素材违规使用行为的公告》：今年第一季度，平台已累计下架违反平台治理规范的漫剧1718部。其中针对近期AI短剧素材违规使用问题频发的情况，平台专项开展集中治理。目前已完成1.5万部作品的全面核查，依规处置违规作品670部。', '36氪获悉，红果短剧官方账号4月6日发布《关于持续治理AI短剧素材违规使用行为的公告》：今年第一季度，平台已累计下架违反平台治理规范的漫剧1718部。其中针对近期AI短剧素材违规使用问题频发的情况，平台专项开展集中治理。目前已完成1.5万部作品的全面核查，依规处置违规作品670部。', 8, '36氪', 'https://36kr.com/newsflashes/3754835385614848?f=rss', '', 'industry', '["\u79d1\u6280", "\u521b\u4e1a", "\u6295\u8d44"]', '2026-04-06 04:24:58.000000', '2026-04-07 06:26:55.682592', 'https://36kr.com/newsflashes/3754835385614848?f=rss', 0.0, 0);
