INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1254, '为了将网页变为应用程序，我们付出了多少努力？（一）', '如今，「网络应用程序（Web App）」的概念已十分流行，那么这个概念本身又有多久的历史呢？十年？二十年？我给出的答案是：三十年。几乎跟万维网和浏览器的历史差不多长。这是一个做了三十多年的「梦」。查看全文', '如今，「网络应用程序（Web App）」的概念已十分流行，那么这个概念本身又有多久的历史呢？十年？二十年？我给出的答案是：三十年。几乎跟万维网和浏览器的历史差不多长。这是一个做了三十多年的「梦」。<a href="https://sspai.com/post/107928" target="_blank">查看全文</a>', 9, '少数派', 'https://sspai.com/post/107928', 'SUNTRISE', 'industry', '["\u6548\u7387", "\u6570\u7801", "\u5de5\u5177"]', '2026-04-03 07:00:47.000000', '2026-04-07 06:26:58.908956', 'https://sspai.com/post/107928', 0.0, 0);
