INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1257, '汇聚热爱，「2050 大会」少数派线下活动邀请你来参与', '「2050大会」是国内科技圈里一个非常独特的存在。这是由中国工程院院士、阿里云创始人王坚博士，通过杭州市云栖科技创新基金会，发起的一项非营利科技活动。每年4月最后一个完整周末，来自世界各地的科技爱好者 ...查看全文', '「2050大会」是国内科技圈里一个非常独特的存在。这是由中国工程院院士、阿里云创始人王坚博士，通过杭州市云栖科技创新基金会，发起的一项非营利科技活动。每年4月最后一个完整周末，来自世界各地的科技爱好者 ...<a href="https://sspai.com/post/108202" target="_blank">查看全文</a>', 9, '少数派', 'https://sspai.com/post/108202', '老麦', 'industry', '["\u6548\u7387", "\u6570\u7801", "\u5de5\u5177"]', '2026-04-02 10:26:36.000000', '2026-04-07 06:26:58.908988', 'https://sspai.com/post/108202', 0.0, 0);
